package com.hogaria.service;
import com.hogaria.dto.PlanningDtos.*;import com.hogaria.entity.*;import com.hogaria.exception.*;import com.hogaria.repository.*;import org.springframework.stereotype.Service;import java.time.*;import java.util.*;
@Service public class HabitService { private final HabitRepository repo; private final HabitCheckinRepository checkRepo; private final FinancialProfileRepository pr;
public HabitService(HabitRepository repo,HabitCheckinRepository checkRepo,FinancialProfileRepository pr){this.repo=repo;this.checkRepo=checkRepo;this.pr=pr;} private void own(UUID u,UUID p){pr.findByIdAndUserId(p,u).orElseThrow(()->new ForbiddenException("Profile does not belong to user"));}
public List<HabitResponse> list(UUID u,UUID p){own(u,p); return repo.findByProfileId(p).stream().map(h->new HabitResponse(h.getId(),h.getProfileId(),h.getName(),h.getFrequency(),h.getActive())).toList();}
public HabitResponse create(UUID u,UUID p,HabitCreateRequest r){own(u,p); var h=repo.save(Habit.builder().profileId(p).name(r.name()).description(r.description()).area("FINANZAS").frequency(r.frequency()).active(true).build()); return new HabitResponse(h.getId(),p,h.getName(),h.getFrequency(),h.getActive());}
public HabitCheckinResponse check(UUID u,UUID p,UUID hid,LocalDate d,HabitCheckinRequest r){own(u,p); var h=repo.findById(hid).orElseThrow(()->new NotFoundException("Habit not found")); if(!h.getProfileId().equals(p)) throw new ForbiddenException("Habit not in profile"); var c=checkRepo.findByHabitIdAndCheckDate(hid,d).orElseGet(()->HabitCheckin.builder().habitId(hid).checkDate(d).build()); c.setDone(Boolean.TRUE.equals(r.done())); c.setNotes(r.notes()); c=checkRepo.save(c); return new HabitCheckinResponse(c.getId(),hid,d,c.getDone());}
}
